    private double calculateNewBalance(double currentBalance, double amount, String type) {
        switch (type.toLowerCase()) {
            case "deposit":
                return currentBalance + amount;
            case "withdraw":
                return currentBalance - amount;
            case "transfer":
                return currentBalance - amount;
            default:
                return currentBalance;
        }
    }
    
