    private String encrypt(String plainText) throws Exception {
        if (secretKey == null) {
            throw new Exception("Encryption key not available");
        }
        
        Cipher cipher = Cipher.getInstance("AES/CBC/PKCS7Padding");
        cipher.init(Cipher.ENCRYPT_MODE, secretKey);
        
        byte[] iv = cipher.getIV();
        prefs.edit().putString(IV_KEY, Base64.encodeToString(iv, Base64.DEFAULT)).apply();
        
        byte[] encrypted = cipher.doFinal(plainText.getBytes());
        return Base64.encodeToString(encrypted, Base64.DEFAULT);
    }
    
    private String decrypt(String encryptedText) throws Exception {
        if (secretKey == null) {
            throw new Exception("Decryption key not available");
        }
        
        byte[] iv = Base64.decode(prefs.getString(IV_KEY, ""), Base64.DEFAULT);
        Cipher cipher = Cipher.getInstance("AES/CBC/PKCS7Padding");
        IvParameterSpec ivSpec = new IvParameterSpec(iv);
        cipher.init(Cipher.DECRYPT_MODE, secretKey, ivSpec);
        
        byte[] decrypted = cipher.doFinal(Base64.decode(encryptedText, Base64.DEFAULT));
        return new String(decrypted);
    }
    
